    if module != "relocation_jobs.scrape_jobs":
        modules.append("relocation_jobs.scrape_jobs")
    for mod in modules:
        monkeypatch.setattr(f"{mod}.requests.get", fake_get)
        monkeypatch.setattr(f"{mod}.requests.post", fake_post)
    return calls

