"""Panel subprocess IPC: progress, review, and activity reporting."""

from __future__ import annotations

import json
import os
from collections.abc import Callable

_progress_reporter: Callable[[dict], None] | None = None
_review_reporter: Callable[[dict], None] | None = None


def emit_panel_ipc(kind: str, payload: dict) -> None:
    """Stdout markers consumed by panel_server when scraping in a subprocess."""
    if os.environ.get("PANEL_SCRAPE_CHILD"):
        print(f"@@{kind}@@{json.dumps(payload, separators=(',', ':'))}", flush=True)


def report_activity(message: str, *, detail: str = "") -> None:
    message = (message or "").strip()
    if not message:
        return
    emit_panel_ipc("ACTIVITY", {"message": message, "detail": (detail or "").strip()})


def set_progress_reporter(reporter: Callable[[dict], None] | None) -> None:
    global _progress_reporter
    _progress_reporter = reporter


def clear_progress_reporter() -> None:
    set_progress_reporter(None)


def set_review_reporter(reporter: Callable[[dict], None] | None) -> None:
    global _review_reporter
    _review_reporter = reporter


def clear_review_reporter() -> None:
    set_review_reporter(None)


def report_progress(
    *,
    current: int,
    total: int,
    company: str | None = None,
    status: str = "",
    new_jobs: int | None = None,
) -> None:
    payload = {
        "current": current,
        "total": total,
        "company": company,
        "status": status,
    }
    if new_jobs is not None:
        payload["new_jobs"] = int(new_jobs)
    if _progress_reporter:
        _progress_reporter(payload)
    emit_panel_ipc("PROGRESS", payload)


def report_review_jobs(
    *,
    included: list[dict],
    filtered: list[dict],
    entry_builder,
) -> None:
    payload = {
        "included": [e for j in included if (e := entry_builder(j))],
        "filtered": [e for j in filtered if (e := entry_builder(j))],
    }
    if _review_reporter:
        _review_reporter(payload)
    emit_panel_ipc("REVIEW", payload)

"""Deel job board scraper."""

from __future__ import annotations

import re

from relocation_jobs.core.ats_detection import HEADERS, _detect_deel_from_url
from relocation_jobs.scrape.http import httpx, requests
from relocation_jobs.scrape.relevance import is_relevant

_DEEL_POSTING_PATTERNS = (
    re.compile(
        r'\\"id\\":\\"([a-f0-9-]+)\\",\\"jobId\\":\\"[a-f0-9-]+\\",\\"title\\":\\"((?:\\\\.|[^\\"])*)\\"',
        re.I,
    ),
    re.compile(
        r'"id":"([a-f0-9-]+)","jobId":"[a-f0-9-]+","title":"((?:\\.|[^"\\])*)"',
        re.I,
    ),
)


def deel_slug_from_url(board_url: str) -> str:
    m = re.search(r"jobs\.deel\.com/([a-zA-Z0-9_-]+)", board_url, re.I)
    return m.group(1) if m else board_url.rstrip("/").split("/")[-1].split("?")[0]


def parse_deel_jobs(html: str, slug: str, *, relevant_only: bool = True) -> list[dict]:
    jobs: list[dict] = []
    seen: set[str] = set()
    for pattern in _DEEL_POSTING_PATTERNS:
        for m in pattern.finditer(html):
            posting_id = m.group(1)
            title = m.group(2).replace('\\"', '"').replace("\\\\", "\\").strip()
            if not posting_id or not title:
                continue
            if relevant_only and not is_relevant(title):
                continue
            url = f"https://jobs.deel.com/{slug}/job-details/{posting_id}/overview"
            if url in seen:
                continue
            seen.add(url)
            jobs.append({"title": title, "url": url})
        if jobs:
            break
    return jobs


def scrape_deel(board_url: str, *, relevant_only: bool = True) -> list[dict]:
    """Scrape jobs.deel.com boards from embedded jobPostings JSON."""
    detected = _detect_deel_from_url(board_url)
    if not detected[1]:
        return []
    fetch_url = detected[1]
    slug = deel_slug_from_url(fetch_url)

    try:
        r = requests.get(fetch_url, headers=HEADERS, timeout=20)
        r.raise_for_status()
    except Exception as e:
        print(f"    Deel error ({fetch_url}): {e}")
        return []

    return parse_deel_jobs(r.text, slug, relevant_only=relevant_only)


async def scrape_deel_async(
    client: httpx.AsyncClient,
    board_url: str,
    *,
    relevant_only: bool = True,
) -> list[dict]:
    detected = _detect_deel_from_url(board_url)
    if not detected[1]:
        return []
    fetch_url = detected[1]
    slug = deel_slug_from_url(fetch_url)

    try:
        r = await client.get(fetch_url, timeout=20.0)
        r.raise_for_status()
    except Exception as e:
        print(f"    Deel error ({fetch_url}): {e}")
        return []

    return parse_deel_jobs(r.text, slug, relevant_only=relevant_only)

"""Join.com job board scraper."""

from __future__ import annotations

import json
import re

from relocation_jobs.core.ats_detection import HEADERS, _detect_join_from_url
from relocation_jobs.scrape.http import httpx, requests
from relocation_jobs.scrape.relevance import is_relevant


def parse_join_next_data(html: str) -> tuple[str | None, int | None, list[dict]]:
    m = re.search(r'<script id="__NEXT_DATA__"[^>]*>(.*?)</script>', html, re.S)
    if not m:
        return None, None, []
    try:
        data = json.loads(m.group(1))
    except json.JSONDecodeError:
        return None, None, []
    state = data.get("props", {}).get("pageProps", {}).get("initialState", {})
    company = state.get("company") or {}
    jobs_block = state.get("jobs") or {}
    return (
        company.get("domain"),
        company.get("id"),
        list(jobs_block.get("items") or []),
    )


def join_jobs_from_items(
    items: list[dict],
    slug: str,
    *,
    relevant_only: bool = True,
) -> list[dict]:
    base = f"https://join.com/companies/{slug}"
    jobs: list[dict] = []
    seen: set[str] = set()
    for item in items:
        title = (item.get("title") or "").strip()
        id_param = (item.get("idParam") or "").strip()
        if not title or not id_param:
            continue
        if relevant_only and not is_relevant(title):
            continue
        url = f"{base}/{id_param}"
        if url in seen:
            continue
        seen.add(url)
        jobs.append({"title": title, "url": url})
    return jobs


def fetch_join_items_via_api(
    company_id: int,
    *,
    headers: dict | None = None,
) -> list[dict]:
    hdrs = headers or HEADERS
    items: list[dict] = []
    page = 1
    while page <= 20:
        try:
            r = requests.get(
                f"https://join.com/api/public/companies/{company_id}/jobs",
                headers={**hdrs, "Accept": "application/json"},
                params={"page": page, "pageSize": 100},
                timeout=15,
            )
            r.raise_for_status()
            data = r.json()
        except Exception:
            break
        batch = list(data.get("items") or [])
        if not batch:
            break
        items.extend(batch)
        pagination = data.get("pagination") or {}
        page_count = int(pagination.get("pageCount") or 1)
        if page >= page_count:
            break
        page += 1
    return items


def scrape_join(careers_url: str, *, relevant_only: bool = True) -> list[dict]:
    """Scrape join.com company boards via __NEXT_DATA__ and public jobs API."""
    detected = _detect_join_from_url(careers_url)
    if not detected[1]:
        return []
    board_url = detected[1]
    slug_m = re.search(r"join\.com/companies/([a-zA-Z0-9_-]+)", board_url, re.I)
    slug = slug_m.group(1) if slug_m else board_url.rstrip("/").split("/")[-1]

    try:
        r = requests.get(board_url, headers=HEADERS, timeout=15)
        r.raise_for_status()
    except Exception as e:
        print(f"    Join error ({board_url}): {e}")
        return []

    slug_from_page, company_id, items = parse_join_next_data(r.text)
    if slug_from_page:
        slug = slug_from_page

    if company_id:
        api_items = fetch_join_items_via_api(company_id)
        if api_items:
            items = api_items

    return join_jobs_from_items(items, slug, relevant_only=relevant_only)


async def scrape_join_async(
    client: httpx.AsyncClient,
