        page = 1
        while page <= 20:
            try:
                api_r = await client.get(
                    f"https://join.com/api/public/companies/{company_id}/jobs",
                    headers={"Accept": "application/json"},
                    params={"page": page, "pageSize": 100},
                    timeout=15.0,
                )
                api_r.raise_for_status()
